dec:
margin-top: 18pt;
  margin-bottom: 18pt;
  padding-inline-start: 18pt;
  border-inline-start: 2pt solid var(--doc-lines-color);

font-family: var(--doc-font-quote);
  font-size: var(--doc-body-size);
  color: var(--doc-secondary-color);
  line-height: var(--doc-quote-line-height);
  text-indent: 0;
  margin: 0;
  font-style: italic;

font-family: var(--doc-font-caption);
  display: block;
  text-align: end;
  margin-top: 6pt;
  font-size: var(--doc-caption-size);
  color: var(--doc-primary-color);
  font-style: normal;
  font-weight: 700;
